  /**
   * Update Epic metadata
   */
  async updateEpic(epicId: string, updates: UpdateEpicRequest): Promise<Epic> {
    const epicRef = this.db.collection('epics').doc(epicId);
    const doc = await epicRef.get();
    if (!doc.exists) {
      throw new Error(`Epic ${epicId} not found`);
    }

    const now = new Date().toISOString();
    const updateData: Record<string, unknown> = {
      updatedAt: now,
    };

    // Only add defined fields
    if (updates.title !== undefined) updateData.title = updates.title;
    if (updates.description !== undefined) updateData.description = updates.description;
    if (updates.status !== undefined) updateData.status = updates.status;
    if (updates.priority !== undefined) updateData.priority = updates.priority;
    if (updates.tags !== undefined) updateData.tags = updates.tags;
    if (updates.ownerId !== undefined) updateData.ownerId = updates.ownerId;
    if (updates.jiraKey !== undefined) updateData.jiraKey = updates.jiraKey;
    if (updates.jiraSyncEnabled !== undefined) updateData.jiraSyncEnabled = updates.jiraSyncEnabled;
    if (updates.githubRepoUrl !== undefined) updateData.githubRepoUrl = updates.githubRepoUrl;
    if (updates.ciAutoValidate !== undefined) updateData.ciAutoValidate = updates.ciAutoValidate;
    if (updates.ciDeployPreview !== undefined) updateData.ciDeployPreview = updates.ciDeployPreview;

    // Add completedAt if status is changing to done
    if (updates.status === 'done') {
      updateData.completedAt = now;
    }

    await epicRef.update(updateData);
    const updated = await epicRef.get();
    return updated.data() as Epic;
  }

  /**
   * Delete an Epic and all its tasks/features
   */
  /**
   * Soft delete an Epic and all its children (tasks, features, assets)
   * Uses batch operations for optimal performance (2-4 queries instead of 63-223)
   *
   * @param epicId - Epic ID to soft delete
   * @param deletedBy - User ID or session ID performing the deletion
   */
  async deleteEpic(epicId: string, deletedBy?: string): Promise<void> {
    const now = new Date().toISOString();

    // Step 1: Batch query all child entities in parallel
    const [tasks, assetsSnapshot] = await Promise.all([
      this.listTasks(epicId),
      this.db.collection('uiAssets').where('epicId', '==', epicId).get()
    ]);

    // Step 2: Batch query features for all tasks
    const taskIds = tasks.map(t => t.id);
    const featuresByTask = await this.listFeaturesForTasks(taskIds);
    const allFeatures = Array.from(featuresByTask.values()).flat();

    log.info(`Soft deleting epic ${epicId}: ${tasks.length} tasks, ${allFeatures.length} features, ${assetsSnapshot.docs.length} assets`);

    // Step 3: Batch update all entities (max 500 per batch)
    const allUpdates = [
      // Features
      ...allFeatures.map(f => ({
        ref: this.db.collection('features').doc(f.id),
        data: { deletedAt: now, deletedBy, updatedAt: now }
      })),
      // Tasks
      ...tasks.map(t => ({
        ref: this.db.collection('epicTasks').doc(t.id),
        data: { deletedAt: now, deletedBy, updatedAt: now }
      })),
      // Assets
      ...assetsSnapshot.docs.map(doc => ({
        ref: doc.ref,
        data: { deletedAt: now, deletedBy, updatedAt: now }
      })),
      // Epic itself
      {
        ref: this.db.collection('epics').doc(epicId),
        data: { deletedAt: now, deletedBy, updatedAt: now }
      }
    ];

    // Split into batches of 500 (Firestore limit)
    for (let i = 0; i < allUpdates.length; i += 500) {
      const batch = this.db.batch();
      const batchUpdates = allUpdates.slice(i, i + 500);

      for (const { ref, data } of batchUpdates) {
        batch.update(ref, data);
      }

      await batch.commit();
      log.info(`Batch ${Math.floor(i / 500) + 1} committed: ${batchUpdates.length} updates`);
    }

    log.info(`Epic ${epicId} and all children soft deleted`);
  }

  /**
   * Get the next sequence number for an Epic shortKey
   * Uses exponential backoff retry for high-concurrency scenarios
   */
  async getNextEpicSequence(orgId: string, shortKey: string): Promise<number> {
    const upperKey = shortKey.toUpperCase();

    // Use a counter document to track sequences
    const counterRef = this.db.collection('epicCounters').doc(`${orgId}:${upperKey}`);

    const MAX_RETRIES = 3;
    let lastError: Error | null = null;

    for (let attempt = 0; attempt < MAX_RETRIES; attempt++) {
      try {
        const result = await this.db.runTransaction(async (transaction) => {
          const counterDoc = await transaction.get(counterRef);

          let nextNum: number;
          if (counterDoc.exists) {
            const data = counterDoc.data();
            nextNum = (data?.sequence || 0) + 1;
          } else {
            nextNum = 1;
          }

          transaction.set(counterRef, { orgId, shortKey: upperKey, sequence: nextNum }, { merge: true });
          return nextNum;
        });

        return result;
      } catch (error) {
        lastError = error as Error;
        if (attempt < MAX_RETRIES - 1) {
          // Exponential backoff: 100ms, 200ms, 400ms
          await new Promise(resolve => setTimeout(resolve, 100 * Math.pow(2, attempt)));
        }
      }
    }

    throw lastError || new Error('Failed to generate Epic sequence after retries');
  }

