  async acceptInvitation(inviteId: string, userId: string, userEmail: string): Promise<OrganizationInvitation> {
    const inviteRef = this.db.collection('invitations').doc(inviteId);
    const doc = await inviteRef.get();
    if (!doc.exists) {
      throw new Error(`Invitation ${inviteId} not found`);
