  /**
   * Create a feature within a task
   */
  async createFeature(request: CreateFeatureRequest): Promise<Feature> {
    // Verify task exists and get epicId
    const task = await this.getTask(request.taskId);
    if (!task) {
      throw new Error(`Task ${request.taskId} not found`);
    }

    const now = new Date().toISOString();
    const featureId = uuidv4();

    // Convert partial acceptance criteria to full objects with IDs and status
    const acceptanceCriteria = (request.acceptanceCriteria || []).map(partial => ({
      id: uuidv4(),
      description: partial.description,
      status: 'pending' as const,
      ...(partial.validationType !== undefined && { validationType: partial.validationType }),
    }));

    const feature: Feature = {
      id: featureId,
      taskId: request.taskId,
      epicId: task.epicId,
      title: request.title,
      status: 'draft',  // New features start in draft status (criteria being defined)
      acceptanceCriteria,
      createdAt: now,
      updatedAt: now,
      deletedAt: null, // Soft delete tracking
    };

    // Add optional fields only if defined
    if (request.description !== undefined) feature.description = request.description;
    if (request.assignedAgent !== undefined) feature.assignedAgent = request.assignedAgent;
    if (request.dependsOn !== undefined) feature.dependsOn = request.dependsOn;
    if (request.canParallelize !== undefined) feature.canParallelize = request.canParallelize;
    if (request.estimatedComplexity !== undefined) feature.estimatedComplexity = request.estimatedComplexity;

    await this.db.collection('features').doc(featureId).set(feature);
    return feature;
  }

  /**
   * Get a feature by ID
   * @param featureId - Feature ID to retrieve
   * @param options - Optional settings
   * @param options.includeDeleted - If true, return soft-deleted features (for verification)
   */
  async getFeature(featureId: string, options?: { includeDeleted?: boolean }): Promise<Feature | null> {
    const doc = await this.db.collection('features').doc(featureId).get();
    if (!doc.exists) return null;
    const feature = doc.data() as Feature;
    // Return null if soft-deleted (deletedAt is a timestamp string)
    // Don't filter if deletedAt is null or undefined (not deleted)
    if (feature.deletedAt && !options?.includeDeleted) return null;
    return feature;
  }

  /**
   * List features for a task
   */
  async listFeatures(taskId: string, filters?: FeatureFilters): Promise<Feature[]> {
    let query = this.db.collection('features')
      .where('taskId', '==', taskId)
      .where('deletedAt', '==', null); // Filter soft-deleted at database level

    // Apply Firestore-supported filters
    if (filters?.status) {
      query = query.where('status', '==', filters.status);
    }
    if (filters?.assignedAgent) {
      query = query.where('assignedAgent', '==', filters.assignedAgent);
    }

    const snapshot = await query.orderBy('createdAt', 'asc').get();
    let features = snapshot.docs.map(doc => doc.data() as Feature);

    // Apply in-memory filters
    if (filters?.search) {
      const searchLower = filters.search.toLowerCase();
      features = features.filter(f =>
        f.title.toLowerCase().includes(searchLower) ||
        f.description?.toLowerCase().includes(searchLower)
      );
    }

    return features;
  }

  /**
   * Batch list features for multiple tasks (optimized to avoid N+1 queries)
   * Returns a map of taskId to features array
   */
  async listFeaturesForTasks(taskIds: string[]): Promise<Map<string, Feature[]>> {
    if (taskIds.length === 0) {
      return new Map();
    }

    // Batch query all features for these tasks (Firestore 'in' supports max 10 items)
    const allFeatures: Feature[] = [];
    for (let i = 0; i < taskIds.length; i += 10) {
      const batch = taskIds.slice(i, i + 10);
      const featuresSnapshot = await this.db.collection('features')
        .where('taskId', 'in', batch)
        .where('deletedAt', '==', null) // Filter soft-deleted at database level
        .orderBy('createdAt', 'asc')
        .get();
      const features = featuresSnapshot.docs.map(doc => doc.data() as Feature);
      allFeatures.push(...features);
    }

    // Group features by taskId
    const featuresByTask = new Map<string, Feature[]>();
    for (const feature of allFeatures) {
      if (!featuresByTask.has(feature.taskId)) {
        featuresByTask.set(feature.taskId, []);
      }
      featuresByTask.get(feature.taskId)!.push(feature);
    }

    return featuresByTask;
  }

  /**
   * Update feature metadata
   */
  async updateFeature(featureId: string, updates: UpdateFeatureRequest): Promise<Feature> {
    const featureRef = this.db.collection('features').doc(featureId);
    const doc = await featureRef.get();
    if (!doc.exists) {
      throw new Error(`Feature ${featureId} not found`);
    }

    const now = new Date().toISOString();
    const updateData: Record<string, unknown> = {
      updatedAt: now,
    };

    // Only add defined fields
    if (updates.title !== undefined) updateData.title = updates.title;
    if (updates.description !== undefined) updateData.description = updates.description;
    if (updates.status !== undefined) updateData.status = updates.status;
    if (updates.assignedAgent !== undefined) updateData.assignedAgent = updates.assignedAgent;
    if (updates.dependsOn !== undefined) updateData.dependsOn = updates.dependsOn;
    if (updates.canParallelize !== undefined) updateData.canParallelize = updates.canParallelize;
    if (updates.acceptanceCriteria !== undefined) updateData.acceptanceCriteria = updates.acceptanceCriteria;
    if (updates.result !== undefined) updateData.result = updates.result;
    if (updates.artifacts !== undefined) updateData.artifacts = updates.artifacts;
    if (updates.commit !== undefined) updateData.commit = updates.commit;
    if (updates.qualityGates !== undefined) updateData.qualityGates = updates.qualityGates;
    if (updates.requiresReview !== undefined) updateData.requiresReview = updates.requiresReview;
    if (updates.reviewReasons !== undefined) updateData.reviewReasons = updates.reviewReasons;

    await featureRef.update(updateData);
    const updated = await featureRef.get();
    return updated.data() as Feature;
  }

