  async createOrganization(name: string, ownerId: string): Promise<Organization> {
    const orgId = uuidv4();
    const now = new Date().toISOString();

    const baseSlug = name.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '');

    // Ensure slug uniqueness by checking for collisions
    let slug = baseSlug;
    let suffix = 2;

    while (true) {
      const existingOrgSnapshot = await this.db
        .collection('organizations')
        .where('slug', '==', slug)
        .where('deletedAt', '==', null)
        .limit(1)
        .get();

      if (existingOrgSnapshot.empty) {
        break;
      }

      slug = `${baseSlug}-${suffix}`;
      suffix++;
    }

    if (slug !== baseSlug) {
      log.info({ baseSlug, finalSlug: slug }, 'Slug collision detected, using suffix');
    }

    const org: Organization = {
      id: orgId,
      name,
      ownerId,
      slug,
      createdAt: now,
      updatedAt: now,
      deletedAt: null, // Soft delete tracking
      members: {
        [ownerId]: {
          userId: ownerId,
          role: 'owner',
          joinedAt: now,
        },
      },
    };

    await this.db.collection('organizations').doc(orgId).set(org);
    return org;
  }

  async getOrganization(orgId: string, options?: { includeDeleted?: boolean }): Promise<Organization | null> {
    const doc = await this.db.collection('organizations').doc(orgId).get();
    if (!doc.exists) return null;
    const org = doc.data() as Organization;
    if (org.deletedAt && !options?.includeDeleted) return null;
