  /**
   * Soft delete a team and cascade to related entities
   * - Soft deletes team-scoped shared prompts
   * - Unassigns team from epics (epics stay active)
   * - Soft deletes team skill configs
   * - Soft deletes the team itself
   *
   * Uses batch operations for efficiency (max 500 operations per batch)
   */
  async deleteTeam(teamId: string, deletedBy?: string): Promise<void> {
    const now = new Date().toISOString();

    // Step 1: Get team to verify it exists and get organizationId
    const team = await this.getTeam(teamId);
    if (!team) {
      throw new Error(`Team ${teamId} not found`);
    }

    // Step 2: Query all related entities in parallel
    const [teamPrompts, epicsAssigned] = await Promise.all([
      this.listTeamPrompts(teamId),
      this.listEpics(team.organizationId, { teamId }),
    ]);

    // Step 3: Batch soft delete all entities
    const allUpdates: Array<{ ref: FirebaseFirestore.DocumentReference; data: Record<string, unknown> }> = [];

    // Soft delete team-scoped prompts
    for (const prompt of teamPrompts) {
      allUpdates.push({
        ref: this.db.collection('sharedPrompts').doc(prompt.id),
        data: { deletedAt: now, deletedBy, updatedAt: now },
      });
    }

    // Unassign team from epics (don't delete epics - they belong to org)
    for (const epic of epicsAssigned) {
      allUpdates.push({
        ref: this.db.collection('epics').doc(epic.id),
        data: { teamId: FieldValue.delete(), updatedAt: now },
      });
    }

    // Soft delete the team itself
    allUpdates.push({
      ref: this.db.collection('teams').doc(teamId),
      data: { deletedAt: now, deletedBy, updatedAt: now },
    });

    // Execute updates in batches (max 500 per batch)
    for (let i = 0; i < allUpdates.length; i += 500) {
      const batch = this.db.batch();
      const batchUpdates = allUpdates.slice(i, i + 500);

      for (const { ref, data } of batchUpdates) {
        batch.update(ref, data);
      }

      await batch.commit();
    }
  }

