/**
 * Firestore StateManager Integration Tests
 *
 * These tests run against the Firestore emulator.
 * Start emulator before running: firebase emulators:start --only firestore
 *
 * Set environment: FIRESTORE_EMULATOR_HOST=127.0.0.1:8080
 *
 * TODO: Many tests in this file use outdated API patterns (manager.updateFeatures,
 * getSessionState) that don't work with the Epic→Task→Feature hierarchy.
 * Tests need to be updated to use the new APIs:
 * - createFeature() requires taskId from a claimed Task within an Epic
 * - Features are no longer stored at session level
 *
 * See the Feature Operations describe.skip block for details.
 */

import { describe, it, beforeAll, beforeEach, afterAll, expect } from 'vitest';
import { FirestoreStateManager } from '../server/state/firestore-manager.js';
import { getApps, deleteApp } from 'firebase-admin/app';

// Ensure we're using the emulator
if (!process.env.FIRESTORE_EMULATOR_HOST) {
  process.env.FIRESTORE_EMULATOR_HOST = '127.0.0.1:8088';
}

describe('FirestoreStateManager', () => {
  let manager: FirestoreStateManager;

  beforeAll(() => {
    // Clear any existing apps
    for (const app of getApps()) {
      deleteApp(app);
    }
  });

  beforeEach(() => {
    manager = new FirestoreStateManager();
  });

  afterAll(async () => {
    // Cleanup
    for (const app of getApps()) {
      await deleteApp(app);
    }
  });

  describe('Session Operations', () => {
    it('should create a session', async () => {
      const session = await manager.createSession('Test Session');

      expect(session).toBeDefined();
      expect(session.id).toBeDefined();
      expect(session.name).toBe('Test Session');
      expect(session.status).toBe('active');
      expect(session.createdAt).toBeDefined();
      expect(session.updatedAt).toBeDefined();

      // Cleanup
      await manager.deleteSession(session.id);
    });

    it('should create session with name as ID when useNameAsId is true', async () => {
      const session = await manager.createSession('custom-id-session', true);

      expect(session.id).toBe('custom-id-session');
      expect(session.name).toBe('custom-id-session');

      // Cleanup
      await manager.deleteSession(session.id);
    });

    it('should list sessions sorted by createdAt desc', async () => {
      const session1 = await manager.createSession('Session 1');
      await new Promise(resolve => setTimeout(resolve, 100)); // Small delay
      const session2 = await manager.createSession('Session 2');

      const sessions = await manager.listSessions();

      expect(sessions.length).toBeGreaterThanOrEqual(2);
      // Most recent should be first
      const idx1 = sessions.findIndex(s => s.id === session1.id);
      const idx2 = sessions.findIndex(s => s.id === session2.id);
      expect(idx2).toBeLessThan(idx1);

      // Cleanup
      await manager.deleteSessions([session1.id, session2.id]);
    });

    it('should get a specific session', async () => {
      const created = await manager.createSession('Get Session Test');

      const retrieved = await manager.getSession(created.id);

      expect(retrieved).toBeDefined();
      expect(retrieved!.id).toBe(created.id);
      expect(retrieved!.name).toBe('Get Session Test');

      // Cleanup
      await manager.deleteSession(created.id);
    });

    it('should return null for non-existent session', async () => {
      const session = await manager.getSession('non-existent-id');
      expect(session).toBeNull();
    });

    it('should delete a session and its subcollections', async () => {
      const session = await manager.createSession('Delete Test');

      // Add some data to subcollections
      await manager.logProgress(session.id, { summary: 'Test log' });
      // Note: We can't add features here since features now require Epic→Task hierarchy
      // Just test session deletion with progress logs

      // Delete
      const result = await manager.deleteSession(session.id);
      expect(result).toBe(true);

      // Verify deleted
      const retrieved = await manager.getSession(session.id);
      expect(retrieved).toBeNull();
    });
  });

  // TODO: These tests use outdated API patterns (manager.updateFeatures)
  // that don't account for the Epic→Task→Feature hierarchy.
  // Features now require: 1) Epic, 2) Task within Epic, 3) Feature within Task
  describe.skip('Feature Operations', () => {
    let sessionId: string;

    beforeEach(async () => {
      const session = await manager.createSession('Feature Test Session');
      sessionId = session.id;
    });

    afterAll(async () => {
      // Cleanup any remaining test sessions
      const sessions = await manager.listSessions();
      const testSessions = sessions.filter(s => s.name.includes('Test'));
      await manager.deleteSessions(testSessions.map(s => s.id));
    });

    it('should create a feature', async () => {
      const feature = await manager.updateFeatures(sessionId, {
        featureId: 'feature-1',
        title: 'User Authentication',
        description: 'User login and registration',
        acceptanceCriteria: [
          { id: 'ac-1', description: 'User can register', status: 'pending' },
          { id: 'ac-2', description: 'User can login', status: 'pending' },
        ],
      });

      expect(feature.id).toBe('feature-1');
      expect(feature.title).toBe('User Authentication');
      expect(feature.passes).toBe(false);
      expect(feature.acceptanceCriteria).toHaveLength(2);
    });

    it('should update existing feature', async () => {
      // Create
      await manager.updateFeatures(sessionId, {
        featureId: 'feature-update',
        title: 'Original Title',
        acceptanceCriteria: [{ id: 'ac-1', description: 'Test', status: 'pending' }],
      });

      // Update
      const updated = await manager.updateFeatures(sessionId, {
        featureId: 'feature-update',
        title: 'Updated Title',
        acceptanceCriteria: [{ id: 'ac-1', description: 'Test', status: 'passed' }],
      });

      expect(updated.title).toBe('Updated Title');
      expect(updated.acceptanceCriteria[0].status).toBe('passed');
    });

    it('should auto-pass feature when all criteria pass', async () => {
      // Create with all passed criteria
      const feature = await manager.updateFeatures(sessionId, {
