          { id: 'ac-1', description: 'Criterion 1', status: 'passed' },
          { id: 'ac-2', description: 'Criterion 2', status: 'passed' },
        ],
      });

      expect(feature.passes).toBe(true);
      expect(feature.checkpoint).toBeDefined();
      expect(feature.checkpoint!.summary).toContain('Feature completed');
    });

    it('should get features for session', async () => {
      await manager.updateFeatures(sessionId, {
