      await manager.updateFeatures(sessionId, {
        featureId: 'f1',
        title: 'Feature 1',
        acceptanceCriteria: [{ id: 'ac1', description: 'Test', status: 'pending' }],
      });

      const current = await manager.getCurrentFeature(sessionId);

      expect(current).toBeDefined();
      expect(current!.id).toBe('f1');
    });

    it('should set current feature', async () => {
      await manager.updateFeatures(sessionId, {
        featureId: 'f1',
        title: 'Feature 1',
        acceptanceCriteria: [{ id: 'ac1', description: 'Test', status: 'pending' }],
      });
      await manager.updateFeatures(sessionId, {
        featureId: 'f2',
        title: 'Feature 2',
        acceptanceCriteria: [{ id: 'ac1', description: 'Test', status: 'pending' }],
