      expect(result).toBeDefined();
      expect(result!.feature.passes).toBe(true);
      expect(result!.checkpoint.summary).toBe('Custom checkpoint');
    });

    // Tests for undefined optional fields (Firestore rejects undefined values)
    describe('Undefined Optional Fields', () => {
