          // assignedAgent is intentionally omitted
        });

        expect(feature.id).toBe('no-agent');
        expect(feature.assignedAgent).toBeUndefined();
      });

      it('should create feature without dependsOn', async () => {
        const feature = await manager.updateFeatures(sessionId, {
          featureId: 'no-deps',
          title: 'Feature Without Dependencies',
