      });
      const team2 = await manager.createTeam(org.id, {
        name: 'Team 2',
        description: 'Second team',
        createdBy: testUserId,
      });

      // Create 2 epics
      const epic1 = await manager.createEpic(org.id, {
        title: 'Epic 1',
        description: 'First epic',
        teamId: team1.id,
      }, testUserId);
      const epic2 = await manager.createEpic(org.id, {
        title: 'Epic 2',
        description: 'Second epic',
      }, testUserId);

      // Create 2 tasks for epic1
      const task1 = await manager.createTask({
        epicId: epic1.id,
        title: 'Task 1',
        description: 'First task',
        createdBy: testUserId,
      });
      const task2 = await manager.createTask({
        epicId: epic1.id,
        title: 'Task 2',
        description: 'Second task',
        createdBy: testUserId,
      });

      // Create 2 features for task1
      await manager.createFeature({
        taskId: task1.id,
        title: 'Feature 1',
