      const startTime = Date.now();
      await manager.deleteOrganization(org.id, testUserId);
      const duration = Date.now() - startTime;

      // Verify organization is soft deleted (use includeDeleted to access)
      const orgAfter = await manager.getOrganization(org.id, { includeDeleted: true });
      expect(orgAfter).not.toBeNull();
      expect(orgAfter!.deletedAt).toBeDefined();
      expect(orgAfter!.deletedBy).toBe(testUserId);

      // Verify teams are soft deleted (use includeDeleted to access)
      const team1After = await manager.getTeam(team1.id, { includeDeleted: true });
      const team2After = await manager.getTeam(team2.id, { includeDeleted: true });
      expect(team1After!.deletedAt).toBeDefined();
      expect(team2After!.deletedAt).toBeDefined();

      // Verify epics are soft deleted (use includeDeleted to access)
      const epic1After = await manager.getEpic(epic1.id, { includeDeleted: true });
      const epic2After = await manager.getEpic(epic2.id, { includeDeleted: true });
      expect(epic1After!.deletedAt).toBeDefined();
      expect(epic2After!.deletedAt).toBeDefined();

      // Verify tasks are soft deleted (use includeDeleted to access)
      const task1After = await manager.getTask(task1.id, { includeDeleted: true });
      const task2After = await manager.getTask(task2.id, { includeDeleted: true });
      expect(task1After!.deletedAt).toBeDefined();
      expect(task2After!.deletedAt).toBeDefined();

      // Verify features are soft deleted
      const featuresAfter = await manager.listFeatures(task1.id);
      expect(featuresAfter).toHaveLength(0); // Filtered by deletedAt

      // Verify invitation is soft deleted
      const invitationAfter = await manager.getInvitation(invitation.id, { includeDeleted: true });
      expect(invitationAfter!.deletedAt).toBeDefined();

      // Verify org prompt is soft deleted
      const orgPromptAfter = await manager.getSharedPrompt(orgPrompt.id, { includeDeleted: true });
      expect(orgPromptAfter!.deletedAt).toBeDefined();

      // Performance check: Should complete in reasonable time
      console.log(`[Performance] Deleted org with 2 teams, 2 epics, 2 tasks, 2 features in ${duration}ms`);
      expect(duration).toBeLessThan(10000); // 10 seconds max
    });

    it('should filter soft-deleted org entities from list queries', async () => {
      // Create 2 organizations
      const org1 = await manager.createOrganization('Active Org', testUserId);
      const org2 = await manager.createOrganization('To Delete Org', testUserId);

      // Create team in org2
      await manager.createTeam(org2.id, {
        name: 'Team in Org2',
        createdBy: testUserId,
      });

      // Create epic in org2
      await manager.createEpic(org2.id, {
        title: 'Epic in Org2',
      }, testUserId);

      // Verify both orgs have teams/epics
      const teamsBefore = await manager.listOrganizationTeams(org2.id);
      const epicsBefore = await manager.listEpics(org2.id);
      expect(teamsBefore.length).toBeGreaterThan(0);
      expect(epicsBefore.length).toBeGreaterThan(0);

      // Soft delete org2
      await manager.deleteOrganization(org2.id, testUserId);

      // Verify org2 entities are filtered from lists
      const teamsAfter = await manager.listOrganizationTeams(org2.id);
      const epicsAfter = await manager.listEpics(org2.id);
      expect(teamsAfter).toHaveLength(0);
      expect(epicsAfter).toHaveLength(0);

      // Verify org1 is still active
      const org1After = await manager.getOrganization(org1.id);
      expect(org1After!.deletedAt).toBeFalsy(); // null or undefined = not deleted

      // Cleanup
      await manager.deleteOrganization(org1.id, testUserId);
    });

    it('should handle org deletion with no related entities', async () => {
      // Create empty organization
      const org = await manager.createOrganization('Empty Org', testUserId);

      // Soft delete immediately
      await manager.deleteOrganization(org.id, testUserId);

      // Verify org is soft deleted
      const orgAfter = await manager.getOrganization(org.id, { includeDeleted: true });
      expect(orgAfter!.deletedAt).toBeDefined();
      expect(orgAfter!.deletedBy).toBe(testUserId);
    });
  });
});

